# Self-review and fixes
def generate_secure_key(password: str, salt: bytes = None) -> bytes:
    if salt is None:
        salt = os.urandom(16)
    kdf = PBKDF2HMAC(
        algorithm=hashes.SHA256(),
        length=32,
        salt=salt,
        iterations=100000,
    )
    key = base64.urlsafe_b64encode(kdf.derive(password.encode()))
    return key

def encrypt_credit_card(card_number: str, config: configparser.ConfigParser) -> str:
    # Use a salt for key derivation
    salt = base64.b64decode(config['ENCRYPTION']['SALT'])
    key = generate_secure_key(config['ENCRYPTION']['PASSWORD'], salt)
    f = Fernet(key)
    encrypted = f.encrypt(card_number.encode())
    return base64.b64encode(encrypted).decode()

def decrypt_credit_card(encrypted_card: str, config: configparser.ConfigParser) -> str:
    salt = base64.b64decode(config['ENCRYPTION']['SALT'])
    key = generate_secure_key(config['ENCRYPTION']['PASSWORD'], salt)
    f = Fernet(key)
    decrypted = f.decrypt(base64.b64decode(encrypted_card.encode()))
    return decrypted.decode()

